import React from "react";
import { motion } from "framer-motion";
import logo from "../assets/logo.png"; // your logo path

const Home = () => {
  return (
    <div className="relative flex flex-col items-center justify-center min-h-screen bg-gradient-to-b from-[#0A0A0A] to-[#111111] text-white overflow-hidden">

      {/* Animated Logo */}
      <motion.img
        src={logo}
        alt="Brand Logo"
        className="w-48 md:w-56 lg:w-64 mb-8"
        initial={{ opacity: 0, scale: 0.7, y: -30 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        transition={{ duration: 1.2, ease: "easeOut" }}
      />

      {/* Hero Message */}
      <motion.h1
        className="text-3xl md:text-5xl font-bold text-center tracking-wide"
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.4, duration: 1 }}
      >
        Welcome to Godemar’s Empire
      </motion.h1>

      <motion.p
        className="text-lg md:text-xl mt-4 text-gray-300 text-center max-w-xl"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.8, duration: 1 }}
      >
        Innovating beyond boundaries — where creativity meets impact.
      </motion.p>

    </div>
  );
};

export default Home;
